use crate::calc::TokenKind::{TokNumber, TokPlus, TokMinus, TokStar, TokSlash, TokCaret, TokLParen, TokRParen, TokEOF};

/// Lex turns an input string into a slice of tokens, terminated by TokEOF.
/// It returns an error on the first unrecognized character.
pub fn lex(input: &str) -> Result<Vec<Token>, String> {
    let mut tokens: Vec<Token> = Vec::new();
    let chars: Vec<char> = input.chars().collect();
    let mut i = 0;

    while i < chars.len() {
        let c = chars[i];
        match c {
            ' ' | '\t' => {
                i += 1;
            }
            '+' => {
                tokens.push(Token { kind: TokPlus, value: 0.0 });
                i += 1;
            }
            '-' => {
                tokens.push(Token { kind: TokMinus, value: 0.0 });
                i += 1;
            }
            '*' => {
                tokens.push(Token { kind: TokStar, value: 0.0 });
                i += 1;
            }
            '/' => {
                tokens.push(Token { kind: TokSlash, value: 0.0 });
                i += 1;
            }
            '^' => {
                tokens.push(Token { kind: TokCaret, value: 0.0 });
                i += 1;
            }
            '(' => {
                tokens.push(Token { kind: TokLParen, value: 0.0 });
                i += 1;
            }
            ')' => {
                tokens.push(Token { kind: TokRParen, value: 0.0 });
                i += 1;
            }
            '0'..='9' | '.' => {
                let start = i;
                while i < chars.len() && (chars[i].is_ascii_digit() || chars[i] == '.') {
                    i += 1;
                }
                let text: String = chars[start..i].iter().collect();
                let val: f64 = text.parse().map_err(|_| format!("invalid number: {:?}", text))?;
                tokens.push(Token { kind: TokNumber, value: val });
            }
            _ => {
                return Err(format!("unexpected character: {:?}", c));
            }
        }
    }

    tokens.push(Token { kind: TokEOF, value: 0.0 });
    Ok(tokens)
}

