impl Parser {
    fn peek(&self) -> Token {
        self.tokens[self.pos].clone()
    }

    fn advance(&mut self) -> Token {
        let t = self.tokens[self.pos].clone();
        self.pos += 1;
        t
    }

    /// Parse evaluates the full expression and verifies all input was consumed.
    pub fn parse(&mut self) -> Result<f64, String> {
        let value = self.parse_add_sub()?;
        if self.peek().kind != TokenKind::TokEOF {
            return Err(format!(
                "unexpected trailing token: {}",
                describe(self.peek().kind)
            ));
        }
        Ok(value)
    }

    fn parse_add_sub(&mut self) -> Result<f64, String> {
        let mut left = self.parse_mul_div()?;
        while self.peek().kind == TokenKind::TokPlus || self.peek().kind == TokenKind::TokMinus {
            let op = self.advance().kind;
            let right = self.parse_mul_div()?;
            if op == TokenKind::TokPlus {
                left += right;
            } else {
                left -= right;
            }
        }
        Ok(left)
    }

    fn parse_mul_div(&mut self) -> Result<f64, String> {
        let mut left = self.parse_power()?;
        while self.peek().kind == TokenKind::TokStar || self.peek().kind == TokenKind::TokSlash {
            let op = self.advance().kind;
            let right = self.parse_power()?;
            if op == TokenKind::TokStar {
                left *= right;
            } else {
                if right == 0.0 {
                    return Err("division by zero".to_string());
                }
                left /= right;
            }
        }
        Ok(left)
    }

    fn parse_power(&mut self) -> Result<f64, String> {
        let base = self.parse_unary()?;
        if self.peek().kind == TokenKind::TokCaret {
            self.advance();
            let exp = self.parse_power()?; // right-associative
            return Ok(int_pow(base, exp));
        }
        Ok(base)
    }

    fn parse_unary(&mut self) -> Result<f64, String> {
        if self.peek().kind == TokenKind::TokMinus {
            self.advance();
            let v = self.parse_unary()?;
            return Ok(-v);
        }
        self.parse_primary()
    }

    fn parse_primary(&mut self) -> Result<f64, String> {
        let t = self.advance();
        match t.kind {
            TokenKind::TokNumber => Ok(t.value),
            TokenKind::TokLParen => {
                let v = self.parse_add_sub()?;
                if self.advance().kind != TokenKind::TokRParen {
                    return Err("expected a closing parenthesis".to_string());
                }
                Ok(v)
            }
            _ => Err(format!("unexpected token: {}", describe(t.kind))),
        }
    }
}

pub fn describe(kind: TokenKind) -> &'static str {
    match kind {
        TokenKind::TokNumber => "number",
        TokenKind::TokPlus => "+",
        TokenKind::TokMinus => "-",
        TokenKind::TokStar => "*",
        TokenKind::TokSlash => "/",
        TokenKind::TokCaret => "^",
        TokenKind::TokLParen => "(",
        TokenKind::TokRParen => ")",
        TokenKind::TokEOF => "end of input",
    }
}

/// intPow raises base to an integer power via repeated multiplication, handling
/// negative exponents by reciprocal. Good enough for a demo calculator.
pub fn int_pow(base: f64, exp: f64) -> f64 {
    let mut result = 1.0;
    let n = exp as i64;
    if n < 0 {
        for _ in 0..(-n) {
            result /= base;
        }
        return result;
    }
    for _ in 0..n {
        result *= base;
    }
    result
}
